def parse_int_list(value, default):
    text = str(value or "").strip()
    if not text:
        return [max(TOP_N, int(v)) for v in default]
    items = []
    for part in text.split(","):
        part = part.strip()
        if not part:
            continue
        try:
            items.append(max(TOP_N, int(part)))
        except Exception:
            continue
    return sorted(set(items)) if items else [max(TOP_N, int(v)) for v in default]


